<template>
<div class="my-popups">
       
<loader :is-visible="isLoading"></loader>
        <div class="modal my-popups right fade d-block" :class="{ show: isShown }">>
            <div role="document" class="modal-dialog" style="max-width: 800px !important;">
                <div class="modal-content">

                    <!-- HEADER -->
                    <div class="modal-header theme-primary partition-full d-flex">
                         <h4 class="modal-title">{{ $t("AccountInformation") }}</h4>
                         
                        <button type="button" class="close" @click="CloseAccount()">
                            <em class="fa fa-times"></em>
                        </button>
                    </div>

                    <!-- BODY -->
                    <div class="modal-body">

                            <div class="tab-content">
                        <!-- SEARCH -->
                        <div class="tab-pane active show">


                            <div class="row">

      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('AccountName')}}:</b> {{AccountProfileData.AccountName || '--'}} </label>
           </div>
      </div>

      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('AccountType')}}:</b> {{AccountProfileData.AccountType || '--'}} </label>
           </div>
      </div>

      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('AccountOwner')}}:</b> {{AccountProfileData.AccountOwner || '--'}}</label>
           </div>
      </div>
      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('Address')}}:</b> {{AccountProfileData.Address || '--'}}</label>
           </div>
      </div>
<div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('City')}}:</b> {{AccountProfileData.City || '--'}}</label>
           </div>
      </div>
      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('State')}}:</b> {{AccountProfileData.State || '--'}}</label>
           </div>
      </div>
      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('Country')}}:</b> {{AccountProfileData.Country || '--'}}</label>
           </div>
      </div>
      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('Zip Code')}}:</b> {{AccountProfileData.ZipCode || '--'}}</label>
           </div>
      </div>
      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('Status')}}:</b> {{AccountProfileData.Status_Name || '--'}}</label>
           </div>
      </div>
      <div class="col-sm-12 col-md-4 col-lg-4">
           <div class="form-group mb-2">
                 <label><b>{{$t('Currency')}}:</b> {{AccountProfileData.Currency || '--'}}</label>
           </div>
      </div>


                            
                        </div>
                        </div>

                        <!-- TABLE -->
<!-- <div class="modal-footer">
                        <div class="col-lg-6 text-right p-0">
                          

                            <a href="javascript:;" 
                            class="btn btn-danger formbtn text-white" v-on:click="Close()">
                                <em class="fa fa-close pr-2"></em>
                                {{ $t("Cancel") }}
                            </a>
                        </div>
                    </div>-->
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>


   
</template>
<script>
import DataServices from "../../services/DataService";
export default {
    props: {
        ClientId: {
            type: Number,
            required: true,
        },
       
    },
    data() {
        return {
            isLoading: false,
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            companyId: null,
            userId: null,
            AccountName:'',
            AccountProfileData:[],
            isShown:false
            
            
        }
    },
    created: async function () {
        var vm = this;
        //debugger
        vm.userId = vm.GetUserInfo.ID;
        vm.user_type= vm.GetUserInfo.UserType;
        vm.companyId = vm.GetUserInfo.CompanyId;
       
        await this.GetAccountProfile();
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true; // adds .show ? triggers transform transition
            }, 50);
        });
    },
    methods: {
        CloseAccount: function () {
            //debugger;
            //this.ViewAccountPopup = false;
            this.$parent.ViewAccountPopup = false;
        },
        GetAccountProfile: async function () {
            //debugger;
           
            var vm = this;
             vm.isLoading = true;
            let Url = `AccountId=${vm.ClientId}&userType=${vm.user_type}`
            await DataServices.GetAccountProfile(Url).then(function (response) {
               // debugger;
               vm.isLoading = false;
                vm.AccountProfileData= response.data[0];
                
            });
        },
       
        
        
        Close: function () {
            var vm=this;
            vm.$router.push({ name: 'ClientListing' });
        }

    }
}
</script>