<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>    
    <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
         <div role="document" class="modal-dialog" style="max-width: 1100px !important;">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{$t("AssignBiller")}}</h4>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div id="divDialogViewContracts" class="modal-body" style="height: auto; min-height: 0px; max-height: none;">

                     <dynamic-form lang="en" ref="AssignBiller" :buttons="buttons"  :schema="FormSchema" 
                         v-on:OnSubmit="SubmitData" :mandatorytext="$t('MandatoryString')">
                      </dynamic-form>

                    <div id="divDialogViewCCoptionTicket" class="w-100 listing mt-4">
                        <div class="table-responsive table-fix-header" style="max-height: 450px; overflow-y: auto;">
                            <table class="table table-bordered dt-responsive nowrap mt-0 mb-0">
                                <thead class="thead-bg">
                                    <tr>
                                        <th class="text-center font-weight-bold" width="10%">S.No</th>
                                        <th class="font-weight-bold" width="80%">{{$t('Biller Name')}} </th>
                                        <th style="width:15%">
                                            <span href="javascript:;">
                                                {{ $t('Flag') }}
                                            </span>
                                        </th>
                                        <th style="width:15%">
                                            <span href="javascript:;">
                                                {{ $t('Invoice') }}
                                            </span>
                                        </th>
                                        <th style="width:15%">
                                            <span href="javascript:;">
                                                {{ $t('Unprocess') }}
                                            </span>
                                        </th>
                                        <th style="width:15%">
                                            <span href="javascript:;">
                                                {{ $t('Billed/Unbilled') }}
                                            </span>
                                        </th>
                                        <th style="width:15%">
                                            <span href="javascript:;">
                                                {{ $t('RateSchedule') }}
                                            </span>
                                        </th>
                                        <th style="width:15%">
                                            <span href="javascript:;">
                                                {{ $t('BillingRule') }}
                                            </span>
                                        </th>
                                        <th style="width:15%">
                                            <span href="javascript:;">
                                                {{ $t('Report') }}
                                            </span>
                                        </th>
                                        <th style="width:15%">
                                            <span href="javascript:;">
                                                {{ $t('Action') }}
                                            </span>
                                        </th>
                                    </tr>
                                </thead>
                                <tbody>
                                    <tr v-for="(c, index) in AssignBillerList" :key="index">
                                        <td class="text-center">
                                            {{ index + 1 }}
                                        </td>
                                        <td>
                                            <span v-html="c.billerName"></span>
                                        </td>
                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isFlag" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isInvoice" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isUnprocess" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isBilledUnbilled" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isRateSchedule" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isBillingRule" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isReport" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>
                                      <td class="action-td">
                                        <div class="action-btns">
                                            <button  class="btn btn-success btn" @click="EditAssignBiller(c.biller,index)" title="Edit">
                                                <i class="fa fa-edit"></i>
                                            </button>
                                            <button  class="btn btn-danger btn" v-on:click="DeleteBiller(c.biller)" title="Delete">
                                                <i class="fa fa-trash"></i>
                                            </button>
                                        </div>
                                    </td>                                    

                                    <tr v-if="AssignBillerList.length === 0">
                                         <td class="text-center text-danger no-record" colspan="9">{{ $t('NoRecordfound') }}</td>                                        
                                    </tr>
                                </tbody>
                            </table>
                            
                        </div>
                    </div>
                </div>

            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
export default {
    props: {
        ClientId: {
            type: Number,
            required: true,
        },
    },
    data() {
        return {
            isLoading: false,
            isShown: false,
            contractName:'',
            clientList:[],
            isFetchingClients: false,
            BillerItemsList:[],
            AssignBillerList:[
                {                    
                    billerName:'',
                    clientId: 0,
                    biller: '',
                    isFlag: false,
                    isInvoice: false,
                    isUnprocess: false,
                    isBilledUnbilled: false,
                    isRateSchedule: false,
                    isBillingRule: false,
                    isReport: false
                }
            ],
            ClientItemsList: [
                {
                    clientId: 0,
                    biller: '',
                    isFlag: false,
                    isInvoice: false,
                    isUnprocess: false,
                    isBilledUnbilled: false,
                    isRateSchedule: false,
                    isBillingRule: false,
                    isReport: false
                }
            ],
             FormSchema: [
                {
                    layoutType: "triple",
                    Data: [                      
                         {
                            astype: "SearchableSelectField",
                            label: this.$t('ContractCompanyName'),
                            name: "ContractName",
                            value: "",
                            placeholder: "Select",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: false,
                                    active: false,
                                    inactive: false,
                                    clear: false
                                },
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: null
                            },
                            disabled: true,
                            validationRules: {
                                "required": true
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('Biller'),
                            name: "Biller",
                            value: "",
                            placeholder: "Select Biller",
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                actionButtons: { selectAll: true,  clear: true },
                                isMultiple: true,
                                itemFields: ['text'],
                                groupFields: [],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                 onChange: null
                            },                            
                            disabled: false,
                            validationRules: {"required": true},
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Flag'),
                            name: "Flag",
                            value: "",
                            placeholder: "",
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Invoice'),
                            name: "Invoice",
                            value: "",
                            placeholder: "",
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Unprocess'),
                            name: "Unprocess",
                            value: "",
                            placeholder: "",
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Billed/Unbilled'),
                            name: "BilledUnbilled",
                            value: "",
                            placeholder: "",
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('RateSchedule'),
                            name: "RateSchedule",
                            value: "",
                            placeholder: "",
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('BillingRule'),
                            name: "BillingRule",
                            value: "",
                            placeholder: "",
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Report'),
                            name: "Report",
                            value: "",
                            placeholder: "",
                        },
                    ],

                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.CreateClone
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.Close,
                },
            ],           
        }
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    computed: { 
          
    },
    created: async function () {
        var vm = this;
        await vm.GetDDLCompanyContractClients();       
        await vm.GetBillerList();
        await vm.FetchData();    
        vm.FormSchema[0].Data[0].value=vm.ClientId;       
    },
    methods: {
         GetDDLCompanyContractClients: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await DataService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                debugger
                vm.$refs.AssignBiller.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.AssignBiller.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
                vm.$refs.AssignBiller.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.AssignBiller.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },      

          GetBillerList: async function () {
            var vm = this;
            vm.isLoading = true;
              try {
                    const url = `reqFrom=all&moduleName=Billing`;
                    const BillerResponse = (await DataService.GetBillerList(url));
                    const BillerResponses=JSON.parse(BillerResponse.data.result)
                    if (BillerResponses) {
                        // vm.$refs.AssignBiller.updateProperty("Biller", "config.options", BillerResponses);
                        // vm.$refs.AssignBiller.UpdateKeyValue();
                    
                        const BillerOptions = BillerResponses.map(item => ({
                            description:  null,
                            displayValue: item.USERNAME,
                            groupText: null,
                            groupValue: null,
                            metaData: item,
                            text: item.USERNAME,     
                            value: item.USERID       
                        }));

                        const billerField = vm.FormSchema[0].Data.find(f => f.name === 'Biller');
                        if (billerField) { billerField.config.options = BillerOptions;}
                        vm.$refs.AssignBiller?.UpdateKeyValue();
                        vm.isLoading = false;
                    }
                } catch (error) {
                    console.error('Error loading Biller:', error);
                }
        },
        
        FetchData: async function () {          
            var vm = this;
            var url = `clientId=${vm.ClientId}`;
            DataService.GetAssignBillerDetail(url).then(response => {
                if (response.status === 200 && response.data?.result) {                    
                    let resultData = response.data.result;                  
                    if (typeof resultData === "string") {
                        resultData = JSON.parse(resultData);
                    }                   
                    if (!Array.isArray(resultData)) {
                        resultData = [resultData];
                    }
                    vm.AssignBillerList = resultData.map(item => ({                        
                        billerName: item.UserName || 0,
                        clientId: item.ClientId || 0,
                        biller: item.BillerId || '',
                        isFlag: item.IsFlag ?? false,
                        isInvoice: item.IsInvoice ?? false,
                        isUnprocess: item.IsUnprocess ?? false,
                        isBilledUnbilled: item.IsBilledUnBilled ?? false,
                        isRateSchedule: item.IsRateSchedule ?? false,
                        isBillingRule: item.IsBillingRule ?? false,
                        isReport: item.IsReport ?? false
                    }));
                }
            });
        },
        
        EditAssignBiller(Id, index) {            
            const vm = this;
            const record = vm.AssignBillerList.find(x => x.biller === Id);           
            vm.FormSchema[0].Data[2].value = record.isFlag ?? false;
            vm.FormSchema[0].Data[3].value = record.isInvoice ?? false;
            vm.FormSchema[0].Data[4].value = record.isUnprocess ?? false;
            vm.FormSchema[0].Data[5].value = record.isBilledUnbilled ?? false;
            vm.FormSchema[0].Data[6].value = record.isRateSchedule ?? false;
            vm.FormSchema[0].Data[7].value = record.isBillingRule ?? false;
            vm.FormSchema[0].Data[8].value = record.isReport ?? false;

            vm.billerId = (record.biller); 
            vm.FormSchema[0].Data[1].value=vm.billerId;            
        },

        SubmitData(formfields) {
            const vm = this;           
                vm.$refs.AssignBiller.validateForm.validate().then(result => {
                if (result) {         
                    const payload = {
                        ClientItemsList: {
                            clientId: vm.ClientId,        
                            billerId: Array.isArray(formfields.Biller) ? formfields.Biller : [formfields.Biller],
                            isFlag: formfields.Flag,
                            isInvoice: formfields.Invoice,
                            isUnprocess: formfields.Unprocess,
                            isBilledUnbilled: formfields.BilledUnbilled,
                            isRateSchedule: formfields.RateSchedule,
                            isBillingRule: formfields.BillingRule,
                            isReport: formfields.Report
                        },
                        BillerItemsList: vm.ClientItemsList,
                        isEditJsonData: false,
                        groupBy: 'Contract'
                    };

                    var obj = JSON.stringify(payload);
                    DataService.SaveAssignBiller(obj).then(response => {
                        if (response.data) {
                            const status = response.data.status || response.data.Status;
                            if (status === "Success") {
                                vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Biller')]),"success",true,vm.$t('Alert'));
                                vm.FetchData();
                                vm.Close();
                            }
                            else {
                                vm.ShowAlert(response.data.msg || vm.$t("ErrorWhileSaving", [vm.$t("Biller")]),"danger",true,vm.$t("Alert"));
                            }
                            vm.isLoading = false;
                        }                    
                    });
                }
            });
        },

        DeleteBiller(Id) {
            var vm = this;
            if (!vm.ClientId) {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
                return;
            }
            vm.confirmR(vm.$t("ConfirmDelete"), true, vm.$t("Delete") + " " + vm.$t("Biller"),
                function () {
                    vm.isLoading = true;                    
                    var url = `groupId=${Id}&groupBy=${'Biller'}`;
                    DataService.DeleteAssignBiller(url).then(function (response) {
                        if (response.status === 200) {
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Biller')]),"success",true,vm.$t("Alert"));
                            vm.FetchData();
                        } else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Biller')]),"error",true,vm.$t("Alert"));
                        }
                        vm.isLoading = false;
                    });
                }
            );
        },

        Close: function () {
            this.$parent.AssignBillerPopup = false;
        }
    }
}
</script>

<style>
    /* Action column cell */
    .action-td {
        width: 15%;
        vertical-align: middle !important;
        text-align: center;
    }

    /* Button wrapper */
    .action-btns {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        gap: 6px;
    }

    /* Extra small buttons */
    .btn-xs {
        padding: 2px 6px;
        font-size: 11px;
        line-height: 1;
        height: 24px;
        min-width: 24px;
    }

    /* Icon size consistency */
    .btn-xs i {
        font-size: 12px;
    }

    .multiselect__content-wrapper{
        z-index: 99999 !important;
    }
    #visiblecolumnSelected  .table-fix-header thead {
        position: relative;
        z-index: 2;
    }
    #divDialogViewCCoptionTicket thead.thead-bg {
        z-index: 1 !important;
    }

</style>

